<template><div class="panel"><div class="section-head"><div><h2>{{ t('logs.loginTitle') }}</h2><p>{{ t('logs.loginDescription') }}</p></div><el-button @click="load">{{ t('common.refresh') }}</el-button></div><el-table :data="rows"><el-table-column prop="loginAt" :label="t('common.time')"/><el-table-column prop="username" :label="t('common.account')"/><el-table-column prop="ipAddress" :label="t('common.ip')"/><el-table-column prop="userAgent" :label="t('common.client')" show-overflow-tooltip/><el-table-column :label="t('common.result')"><template #default="s"><el-tag :type="s.row.success?'success':'danger'">{{s.row.success?t('logs.success'):t('logs.failed')}}</el-tag></template></el-table-column><el-table-column prop="message" :label="t('logs.message')"/></el-table><el-pagination v-model:current-page="query.page" :page-size="query.size" :total="total" layout="total, prev, pager, next" @current-change="load"/></div></template><script setup>import{onMounted,reactive,ref}from'vue';import{useI18n}from'vue-i18n';import http from'../api/http';const{t}=useI18n();const rows=ref([]),total=ref(0);const query=reactive({page:1,size:5});/** 加载登录日志。 */async function load(){const response=await http.get('/system/login-logs',{params:query});rows.value=response.data.items;total.value=response.data.total}onMounted(load)</script>
<!-- 登录日志页面：展示用户登录审计记录。 -->
